    def list_routes(self) -> list[dict]:
        """List all configured routes."""
        response = self._request("GET", "/routes")
        routes = response.json().get("data", [])
        logger.info("Found %d routes", len(routes))
        return routes

    def list_plugins(self) -> list[dict]:
        """List all configured plugins."""
        response = self._request("GET", "/plugins")
        plugins = response.json().get("data", [])
        logger.info("Found %d plugins", len(plugins))
        return plugins

    def delete_service(self, name: str) -> None:
        """Delete a service by name."""
        if not validate_name(name):
            raise ValueError(f"Invalid service name: {name}")
        self._request("DELETE", f"/services/{name}")
        logger.info("Service deleted: %s", name)

    def delete_route(self, name: str) -> None:
        """Delete a route by name."""
        if not validate_name(name):
            raise ValueError(f"Invalid route name: {name}")
        self._request("DELETE", f"/routes/{name}")
        logger.info("Route deleted: %s", name)


